# Create a recurring quarterly access review for Global Administrator eligible assignments
# Requires AccessReview.ReadWrite.All
$body = @{
    displayName            = 'Quarterly Global Admin Eligible Review'
    startDateTime          = '2025-01-01T09:00:00Z'
    instanceDurationInDays = 14
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 3; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    reviewers = @(
        @{ query = '/v1.0/users/<security-reviewer-oid>'; queryType = 'MicrosoftGraph' }
    )
    settings = @{
        mailNotificationsEnabled      = $true
        reminderNotificationsEnabled  = $true
        justificationRequiredOnApproval = $true
        defaultDecisionEnabled        = $true
        defaultDecision               = 'Deny'
        autoApplyDecisionsEnabled     = $true
        recommendationsEnabled         = $true
    }
    scope = @{
        '@odata.type'   = '#microsoft.graph.principalResourceMembershipsScope'
        principalScopes = @( @{ '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
                                query = '/v1.0/users'; queryType = 'MicrosoftGraph' } )
        resourceScopes  = @( @{ '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
                                query = '/beta/roleManagement/directory/roleEligibilityScheduleInstances?$filter=roleDefinitionId eq 62e90394-69f5-4237-9190-012177145e10'
                                queryType = 'MicrosoftGraph' } )
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $body -ContentType 'application/json'

# List all active access review instances for a subscription's privileged roles
$subId = '<subscription-id>'
$scope = "/subscriptions/$subId"

# Get PIM schedule instances (eligible assignments) scoped to the subscription
$schedule = Invoke-MgGraphRequest -Method GET \
  -Uri "https://graph.microsoft.com/v1.0/roleManagement/directory/roleEligibilityScheduleInstances?" +
        "`$filter=directoryScopeId eq '$scope'"

# Create access review scoped to Owner and Contributor on the subscription
$reviewBody = @{
    displayName = 'Monthly Sub Owner/Contributor Review'
    startDateTime = '2025-01-01T00:00:00Z'
    instanceDurationInDays = 7
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 1; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    reviewers = @( @{ query = '/v1.0/users/<owner-reviewer-oid>'; queryType = 'MicrosoftGraph' } )
    settings = @{
        defaultDecision = 'Deny'; autoApplyDecisionsEnabled = $true
        justificationRequiredOnApproval = $true; recommendationsEnabled = $true
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $reviewBody -ContentType 'application/json'
